<?php
 namespace WPAICG\Vector\Providers\Pinecone\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Pinecone_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function get_index_overview_logic(AIPKit_Vector_Pinecone_Strategy $strategyInstance, string $index_name): array|WP_Error { $cache_key = 'aipkit_pinecone_index_overview_' . md5($index_name); $cache_group = 'aipkit_pinecone'; static $request_cache = []; if (isset($request_cache[$cache_key])) { return $request_cache[$cache_key]; } $cached = wp_cache_get($cache_key, $cache_group); if (false !== $cached) { $request_cache[$cache_key] = $cached; return $cached; } $transient = get_transient($cache_key); if (false !== $transient) { wp_cache_set($cache_key, $transient, $cache_group, HOUR_IN_SECONDS); $request_cache[$cache_key] = $transient; return $transient; } $path = '/indexes/' . urlencode($index_name); $description = _request_logic($strategyInstance, 'GET', $path); if (!is_wp_error($description)) { $ttl = (int) apply_filters('aipkit_pinecone_index_overview_cache_ttl', HOUR_IN_SECONDS, $index_name, $description); if ($ttl > 0) { set_transient($cache_key, $description, $ttl); wp_cache_set($cache_key, $description, $cache_group, $ttl); } } $request_cache[$cache_key] = $description; return $description; } function describe_index_logic(AIPKit_Vector_Pinecone_Strategy $strategyInstance, string $index_name): array|WP_Error { $description = get_index_overview_logic($strategyInstance, $index_name); if (is_wp_error($description)) { return $description; } $host = $description['host'] ?? null; if (empty($host)) { $description['total_vector_count'] = 'No Host'; return $description; } $stats_response = _request_logic($strategyInstance, 'POST', '/describe_index_stats', [], 'https://' . $host); if (is_wp_error($stats_response)) { $description['total_vector_count'] = 'Error'; } else { $description['total_vector_count'] = $stats_response['totalVectorCount'] ?? $stats_response['total_vector_count'] ?? 0; if (isset($stats_response['namespaces'])) { $description['namespaces'] = $stats_response['namespaces']; } } return $description; } 